class Solution:
    def numberOfPowerfulInt(self, start: int, finish: int, limit: int, s: str) -> int:
        from itertools import product

        def is_valid(num: int) -> bool:
            # Check if all digits of num are <= limit
            return all(int(digit) <= limit for digit in str(num))

        def has_suffix(num: int, suffix: str) -> bool:
            # Check if the number ends with the given suffix
            return str(num).endswith(suffix)

        def generate_numbers_with_suffix(suffix: str, limit: int, max_length: int) -> set:
            # Generate all numbers with the given suffix, all digits <= limit, and length <= max_length
            result = set()
            suffix_len = len(suffix)
            for length in range(suffix_len, max_length + 1):
                prefix_len = length - suffix_len
                for prefix in product(range(limit + 1), repeat=prefix_len):
                    # Convert prefix to integer
                    prefix_str = ''.join(map(str, prefix))
                    num_str = prefix_str + suffix
                    num = int(num_str)
                    result.add(num)
            return result

        # Determine the maximum length of numbers to consider
        max_length = len(str(finish))
        # Generate all numbers with the suffix s, all digits <= limit
        candidates = generate_numbers_with_suffix(s, limit, max_length)

        # Count how many of these candidates are in the [start, finish] range
        count = 0
        for num in candidates:
            if start <= num <= finish:
                count += 1
        return count
